<?php

namespace SeoPro\Core;

defined( 'ABSPATH' ) || exit;

class Helpers {

	public static function reading_time( string $content ): string {
		$words   = str_word_count( wp_strip_all_tags( $content ) );
		$minutes = max( 1, (int) ceil( $words / 200 ) );
		return sprintf(
			/* translators: %d: minutes. */
			_n( '%d dk okuma', '%d dk okuma', $minutes, 'seopro' ),
			$minutes
		);
	}

	public static function breadcrumb_items(): array {
		$items = [ [ 'label' => __( 'Anasayfa', 'seopro' ), 'url' => home_url( '/' ) ] ];

		if ( is_singular() ) {
			$post_type = get_post_type();
			if ( 'post' === $post_type ) {
				$cats = get_the_category();
				if ( ! empty( $cats ) ) {
					$items[] = [ 'label' => $cats[0]->name, 'url' => get_category_link( $cats[0]->term_id ) ];
				}
			}
			$items[] = [ 'label' => get_the_title(), 'url' => '' ];
		} elseif ( is_category() || is_tag() || is_tax() ) {
			$items[] = [ 'label' => single_term_title( '', false ), 'url' => '' ];
		} elseif ( is_author() ) {
			$items[] = [ 'label' => get_the_author(), 'url' => '' ];
		} elseif ( is_search() ) {
			$items[] = [ 'label' => __( 'Arama', 'seopro' ), 'url' => '' ];
		} elseif ( is_404() ) {
			$items[] = [ 'label' => __( '404', 'seopro' ), 'url' => '' ];
		}

		return $items;
	}

	public static function excerpt( int $words = 0 ): string {
		$words = $words ?: absint( Options::get( 'seopro_excerpt_length' ) );
		return wp_trim_words( get_the_excerpt(), $words, '…' );
	}

