	public static function cat_color( int $term_id ): string {
		$palette = [ '#E11D48', '#2563EB', '#059669', '#D97706', '#7C3AED', '#0891B2', '#DB2777', '#65A30D' ];
		return $palette[ $term_id % count( $palette ) ];
	}

	public static function cat_ink( int $term_id ): string {
		$palette = [ '#BE123C', '#1D4ED8', '#065F46', '#92400E', '#6D28D9', '#155E75', '#BE185D', '#3F6212' ];
		return $palette[ $term_id % count( $palette ) ];
	}

